SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS menu_permissions;
DROP TABLE IF EXISTS audit_log;
DROP TABLE IF EXISTS mutasi_stok;
DROP TABLE IF EXISTS kas;
DROP TABLE IF EXISTS kategori_kas;
DROP TABLE IF EXISTS pembayaran_hutang;
DROP TABLE IF EXISTS hutang;
DROP TABLE IF EXISTS pembayaran_piutang;
DROP TABLE IF EXISTS piutang;
DROP TABLE IF EXISTS pembelian_detail;
DROP TABLE IF EXISTS pembelian;
DROP TABLE IF EXISTS penjualan_detail;
DROP TABLE IF EXISTS penjualan;
DROP TABLE IF EXISTS supplier;
DROP TABLE IF EXISTS pelanggan;
DROP TABLE IF EXISTS produk;
DROP TABLE IF EXISTS kategori_produk;
DROP TABLE IF EXISTS satuan;
DROP TABLE IF EXISTS users;
DROP TABLE IF EXISTS roles;
DROP TABLE IF EXISTS umkm;

CREATE TABLE umkm (
    id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    kode_umkm VARCHAR(30) NOT NULL UNIQUE,
    nama_umkm VARCHAR(150) NOT NULL,
    nama_pemilik VARCHAR(150), alamat TEXT, telepon VARCHAR(30), email VARCHAR(100), jenis_usaha VARCHAR(100), deskripsi TEXT, logo VARCHAR(255),
    status ENUM('aktif','nonaktif') DEFAULT 'aktif', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NULL, is_system TINYINT(1) NOT NULL DEFAULT 1, nama_role VARCHAR(50) NOT NULL, display_name VARCHAR(100) NULL, deskripsi VARCHAR(255), UNIQUE KEY uk_roles_scope_name (umkm_id, nama_role), CONSTRAINT fk_roles_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE users (
    id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NULL, role_id BIGINT UNSIGNED NOT NULL, nama VARCHAR(150) NOT NULL, username VARCHAR(100) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL,
    email VARCHAR(100), telepon VARCHAR(30), reset_token VARCHAR(100) NULL, reset_token_expires_at DATETIME NULL,
    status ENUM('aktif','nonaktif') DEFAULT 'aktif', last_login DATETIME NULL,
    created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    CONSTRAINT fk_users_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE SET NULL,
    CONSTRAINT fk_users_role FOREIGN KEY (role_id) REFERENCES roles(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE kategori_produk (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, nama_kategori VARCHAR(100) NOT NULL, deskripsi VARCHAR(255), created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_kategori_produk_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE satuan (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, nama_satuan VARCHAR(50) NOT NULL UNIQUE, keterangan VARCHAR(255)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE produk (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, kategori_id BIGINT UNSIGNED NOT NULL, satuan_id BIGINT UNSIGNED NOT NULL, kode_produk VARCHAR(50) NOT NULL, barcode VARCHAR(80) NULL, nama_produk VARCHAR(150) NOT NULL, harga_beli DECIMAL(18,2) DEFAULT 0, harga_jual DECIMAL(18,2) DEFAULT 0, stok DECIMAL(18,2) DEFAULT 0, stok_minimum DECIMAL(18,2) DEFAULT 0, gambar_produk VARCHAR(255) NULL, deskripsi TEXT, status ENUM('aktif','nonaktif') DEFAULT 'aktif', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uk_produk_umkm_kode (umkm_id, kode_produk), KEY idx_produk_barcode (barcode), CONSTRAINT fk_produk_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_produk_kategori FOREIGN KEY (kategori_id) REFERENCES kategori_produk(id), CONSTRAINT fk_produk_satuan FOREIGN KEY (satuan_id) REFERENCES satuan(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE pelanggan (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, nama_pelanggan VARCHAR(150) NOT NULL, alamat TEXT, telepon VARCHAR(30), jenis_pelanggan VARCHAR(50), catatan TEXT, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_pelanggan_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE supplier (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, nama_supplier VARCHAR(150) NOT NULL, alamat TEXT, telepon VARCHAR(30), jenis_supplier VARCHAR(50), catatan TEXT, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_supplier_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE penjualan (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, kode_penjualan VARCHAR(50) NOT NULL, tanggal DATETIME NOT NULL, pelanggan_id BIGINT UNSIGNED NULL, user_id BIGINT UNSIGNED NOT NULL, subtotal DECIMAL(18,2) DEFAULT 0, diskon DECIMAL(18,2) DEFAULT 0, is_pajak_enabled TINYINT(1) NOT NULL DEFAULT 0, pajak_persen INT NOT NULL DEFAULT 0, pajak_nominal BIGINT NOT NULL DEFAULT 0, total DECIMAL(18,2) DEFAULT 0, dibayar DECIMAL(18,2) DEFAULT 0, sisa DECIMAL(18,2) DEFAULT 0, metode_pembayaran ENUM('tunai','transfer','kredit') DEFAULT 'tunai', status_pembayaran ENUM('lunas','sebagian','belum_bayar') DEFAULT 'lunas', keterangan TEXT, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uk_penjualan_umkm_kode (umkm_id, kode_penjualan), CONSTRAINT fk_penjualan_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_penjualan_pelanggan FOREIGN KEY (pelanggan_id) REFERENCES pelanggan(id) ON DELETE SET NULL, CONSTRAINT fk_penjualan_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE penjualan_detail (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, penjualan_id BIGINT UNSIGNED NOT NULL, produk_id BIGINT UNSIGNED NOT NULL, qty DECIMAL(18,2) NOT NULL DEFAULT 0, harga DECIMAL(18,2) NOT NULL DEFAULT 0, subtotal DECIMAL(18,2) NOT NULL DEFAULT 0, CONSTRAINT fk_penjualan_detail_penjualan FOREIGN KEY (penjualan_id) REFERENCES penjualan(id) ON DELETE CASCADE, CONSTRAINT fk_penjualan_detail_produk FOREIGN KEY (produk_id) REFERENCES produk(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE pembelian (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, kode_pembelian VARCHAR(50) NOT NULL, tanggal DATETIME NOT NULL, supplier_id BIGINT UNSIGNED NULL, user_id BIGINT UNSIGNED NOT NULL, subtotal DECIMAL(18,2) DEFAULT 0, diskon DECIMAL(18,2) DEFAULT 0, total DECIMAL(18,2) DEFAULT 0, dibayar DECIMAL(18,2) DEFAULT 0, sisa DECIMAL(18,2) DEFAULT 0, metode_pembayaran ENUM('tunai','transfer','hutang') DEFAULT 'tunai', status_pembayaran ENUM('lunas','sebagian','belum_bayar') DEFAULT 'lunas', keterangan TEXT, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uk_pembelian_umkm_kode (umkm_id, kode_pembelian), CONSTRAINT fk_pembelian_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_pembelian_supplier FOREIGN KEY (supplier_id) REFERENCES supplier(id) ON DELETE SET NULL, CONSTRAINT fk_pembelian_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE pembelian_detail (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, pembelian_id BIGINT UNSIGNED NOT NULL, produk_id BIGINT UNSIGNED NOT NULL, qty DECIMAL(18,2) NOT NULL DEFAULT 0, harga DECIMAL(18,2) NOT NULL DEFAULT 0, subtotal DECIMAL(18,2) NOT NULL DEFAULT 0, CONSTRAINT fk_pembelian_detail_pembelian FOREIGN KEY (pembelian_id) REFERENCES pembelian(id) ON DELETE CASCADE, CONSTRAINT fk_pembelian_detail_produk FOREIGN KEY (produk_id) REFERENCES produk(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE piutang (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, penjualan_id BIGINT UNSIGNED NOT NULL, pelanggan_id BIGINT UNSIGNED NULL, tanggal_piutang DATE NOT NULL, jatuh_tempo DATE NULL, total_piutang DECIMAL(18,2) NOT NULL DEFAULT 0, total_bayar DECIMAL(18,2) NOT NULL DEFAULT 0, sisa_piutang DECIMAL(18,2) NOT NULL DEFAULT 0, status ENUM('belum_lunas','sebagian','lunas') DEFAULT 'belum_lunas', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_piutang_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_piutang_penjualan FOREIGN KEY (penjualan_id) REFERENCES penjualan(id) ON DELETE CASCADE, CONSTRAINT fk_piutang_pelanggan FOREIGN KEY (pelanggan_id) REFERENCES pelanggan(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE pembayaran_piutang (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, piutang_id BIGINT UNSIGNED NOT NULL, tanggal_bayar DATETIME NOT NULL, nominal_bayar DECIMAL(18,2) NOT NULL DEFAULT 0, metode_pembayaran ENUM('tunai','transfer') DEFAULT 'tunai', keterangan TEXT, user_id BIGINT UNSIGNED NOT NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_pembayaran_piutang_piutang FOREIGN KEY (piutang_id) REFERENCES piutang(id) ON DELETE CASCADE, CONSTRAINT fk_pembayaran_piutang_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE hutang (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, pembelian_id BIGINT UNSIGNED NOT NULL, supplier_id BIGINT UNSIGNED NULL, tanggal_hutang DATE NOT NULL, jatuh_tempo DATE NULL, total_hutang DECIMAL(18,2) NOT NULL DEFAULT 0, total_bayar DECIMAL(18,2) NOT NULL DEFAULT 0, sisa_hutang DECIMAL(18,2) NOT NULL DEFAULT 0, status ENUM('belum_lunas','sebagian','lunas') DEFAULT 'belum_lunas', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_hutang_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_hutang_pembelian FOREIGN KEY (pembelian_id) REFERENCES pembelian(id) ON DELETE CASCADE, CONSTRAINT fk_hutang_supplier FOREIGN KEY (supplier_id) REFERENCES supplier(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE pembayaran_hutang (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, hutang_id BIGINT UNSIGNED NOT NULL, tanggal_bayar DATETIME NOT NULL, nominal_bayar DECIMAL(18,2) NOT NULL DEFAULT 0, metode_pembayaran ENUM('tunai','transfer') DEFAULT 'tunai', keterangan TEXT, user_id BIGINT UNSIGNED NOT NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_pembayaran_hutang_hutang FOREIGN KEY (hutang_id) REFERENCES hutang(id) ON DELETE CASCADE, CONSTRAINT fk_pembayaran_hutang_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE kategori_kas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, nama_kategori VARCHAR(100) NOT NULL, jenis ENUM('masuk','keluar') NOT NULL, keterangan VARCHAR(255), created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_kategori_kas_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE kas (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, tanggal DATETIME NOT NULL, kategori_kas_id BIGINT UNSIGNED NOT NULL, jenis ENUM('masuk','keluar') NOT NULL, nominal DECIMAL(18,2) NOT NULL DEFAULT 0, referensi_tipe VARCHAR(50) NULL, referensi_id BIGINT UNSIGNED NULL, keterangan TEXT, user_id BIGINT UNSIGNED NOT NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_kas_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_kas_kategori FOREIGN KEY (kategori_kas_id) REFERENCES kategori_kas(id), CONSTRAINT fk_kas_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE mutasi_stok (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NOT NULL, produk_id BIGINT UNSIGNED NOT NULL, tanggal DATETIME NOT NULL, jenis_mutasi ENUM('pembelian','penjualan','penyesuaian','retur','koreksi') NOT NULL, qty_masuk DECIMAL(18,2) NOT NULL DEFAULT 0, qty_keluar DECIMAL(18,2) NOT NULL DEFAULT 0, stok_sebelum DECIMAL(18,2) NOT NULL DEFAULT 0, stok_sesudah DECIMAL(18,2) NOT NULL DEFAULT 0, referensi_tipe VARCHAR(50) NULL, referensi_id BIGINT UNSIGNED NULL, keterangan TEXT, user_id BIGINT UNSIGNED NOT NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_mutasi_stok_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_mutasi_stok_produk FOREIGN KEY (produk_id) REFERENCES produk(id), CONSTRAINT fk_mutasi_stok_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE menu_permissions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NULL, role_id BIGINT UNSIGNED NOT NULL, menu_key VARCHAR(50) NOT NULL, can_access TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uk_menu_permissions (umkm_id, role_id, menu_key), CONSTRAINT fk_menu_permissions_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE CASCADE, CONSTRAINT fk_menu_permissions_role FOREIGN KEY (role_id) REFERENCES roles(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE audit_log (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, umkm_id BIGINT UNSIGNED NULL, user_id BIGINT UNSIGNED NOT NULL, aktivitas VARCHAR(150) NOT NULL, tabel_ref VARCHAR(100), data_ref_id BIGINT UNSIGNED NULL, keterangan TEXT, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_audit_log_umkm FOREIGN KEY (umkm_id) REFERENCES umkm(id) ON DELETE SET NULL, CONSTRAINT fk_audit_log_user FOREIGN KEY (user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

